def compute_ecc_mode_corrections_default(e, z, x):
    """Newtonian-order eccentric corrections for (2,2), (2,1), (3,3)."""
    u = 1.0 + e * math.cos(z)
    u2 = u * u
    return u2, 0.0, u2, 0.0, u2 * u, 0.0

